import{_ as e,a as o,b as r,c as t,d as i,e as d}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as l,o as s,c as p,a2 as c}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Adicionar canal Dropbox","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/upload/dropbox.md","filePath":"pt-BR/upload/dropbox.md","lastUpdated":1781962217000}'),n={name:"pt-BR/upload/dropbox.md"};function m(h,a,b,u,x,f){return s(),p("div",null,[...a[0]||(a[0]=[c('<h1 id="adicionar-canal-dropbox" tabindex="-1">Adicionar canal Dropbox <a class="header-anchor" href="#adicionar-canal-dropbox" aria-label="Permalink to &quot;Adicionar canal Dropbox&quot;">​</a></h1><p>O canal Dropbox usa uma conta Dropbox como destino de armazenamento.</p><h2 id="o-que-preparar" tabindex="-1">O que preparar <a class="header-anchor" href="#o-que-preparar" aria-label="Permalink to &quot;O que preparar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Uso</th></tr></thead><tbody><tr><td>Conta Dropbox</td><td>Salvar arquivos</td></tr><tr><td>Dropbox App</td><td>Dar acesso por API</td></tr><tr><td>Access Token</td><td>Permitir que o ImgBed use o Dropbox</td></tr><tr><td>Diretório</td><td>Opcional, normalmente <code>imgbed</code></td></tr></tbody></table><h2 id="criar-aplicacao" tabindex="-1">Criar aplicação <a class="header-anchor" href="#criar-aplicacao" aria-label="Permalink to &quot;Criar aplicação&quot;">​</a></h2><p>Abra o Dropbox App Console e crie uma aplicação.</p><p><img src="'+e+'" alt="Criar aplicação" loading="lazy"></p><p>Escolha o escopo conforme a forma de armazenamento desejada. Uma pasta dedicada costuma ser mais fácil de manter.</p><h2 id="configurar-callback" tabindex="-1">Configurar callback <a class="header-anchor" href="#configurar-callback" aria-label="Permalink to &quot;Configurar callback&quot;">​</a></h2><p>Se usar OAuth, adicione a URL de retorno do ImgBed:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://seu-dominio/api/oauth/dropbox/callback</span></span></code></pre></div><p><img src="'+o+'" alt="Configurar callback" loading="lazy"></p><h2 id="adicionar-permissoes" tabindex="-1">Adicionar permissões <a class="header-anchor" href="#adicionar-permissoes" aria-label="Permalink to &quot;Adicionar permissões&quot;">​</a></h2><p>Ative permissões de upload, leitura e exclusão conforme necessário.</p><p><img src="'+r+'" alt="Permissões Dropbox" loading="lazy"></p><h2 id="obter-token" tabindex="-1">Obter Token <a class="header-anchor" href="#obter-token" aria-label="Permalink to &quot;Obter Token&quot;">​</a></h2><p>Obtenha o token pela aplicação ou pelo fluxo de autorização do ImgBed.</p><p><img src="'+t+'" alt="Obter Token" loading="lazy"></p><p>Copie o token e cole no ImgBed.</p><p><img src="'+i+'" alt="Copiar Token" loading="lazy"></p><h2 id="preencher-no-imgbed" tabindex="-1">Preencher no ImgBed <a class="header-anchor" href="#preencher-no-imgbed" aria-label="Permalink to &quot;Preencher no ImgBed&quot;">​</a></h2><p>Em Configurações de upload, escolha <code>Dropbox</code>.</p><table tabindex="0"><thead><tr><th>Campo</th><th>Valor</th></tr></thead><tbody><tr><td>Nome do canal</td><td>Nome reconhecível</td></tr><tr><td>Access Token</td><td>Token do Dropbox</td></tr><tr><td>Diretório</td><td>Opcional; vazio ou <code>imgbed</code></td></tr><tr><td>Observação</td><td>Opcional</td></tr></tbody></table><h2 id="verificacao" tabindex="-1">Verificação <a class="header-anchor" href="#verificacao" aria-label="Permalink to &quot;Verificação&quot;">​</a></h2><p>Depois de salvar, execute consulta de capacidade ou envie uma imagem de teste.</p><p><img src="'+d+'" alt="Consulta de capacidade" loading="lazy"></p><p>Se o arquivo aparecer no Dropbox e o link do ImgBed abrir, o canal está pronto.</p><h2 id="se-falhar" tabindex="-1">Se falhar <a class="header-anchor" href="#se-falhar" aria-label="Permalink to &quot;Se falhar&quot;">​</a></h2><ul><li>Token expirado ou com permissões incompletas.</li><li>Permissões da app alteradas sem nova autorização.</li><li>Diretório com espaços ou barras desnecessárias.</li><li>Dropbox sem espaço disponível.</li></ul>',29)])])}const q=l(n,[["render",m]]);export{k as __pageData,q as default};
